args.TargetContent:
{/* ── SUB-TAB: File Editor (HTML & Binary Uploads) ──────────────────────── */}
{editorSubTab === 'files' && (
  <div className="bg-white dark:bg-slate-900 rounded-[24px] border border-slate-100 dark:border-slate-800 p-6 shadow-sm space-y-5">
    <h4 className="font-black text-sm text-emerald-600 dark:text-emerald-400 border-b border-slate-50 dark:border-slate-800 pb-2">
      {lang === 'ar' ? '📁 تحرير ملفات الدرس مباشرة' : '📁 Direct Lesson File Editor'}
    </h4>

    {/* ── HTML Files Section ────────────────────────────── */}
    <div className="space-y-3">
      <p className="text-[10px] font-black text-slate-400 uppercase tracking-wider">
        {lang === 'ar' ? 'ملفات HTML — الخارطة الذهنية والاختبار الخارجي' : 'HTML Files — Mindmap & External Quiz'}
      </p>
      <div className="flex flex-wrap gap-2">
        {editingLesson.mindmapFile && (
          <button
            onClick={() => loadFileForEditing(`${editingLesson.folder}/${editingLesson.mindmapFile}`)}
            className={`flex items-center gap-2 px-4 py-2.5 rounded-xl text-xs font-black border transition-all ${
              fileEditorPath === `${editingLesson.folder}/${editingLesson.mindmapFile}`
                ? 'bg-amber-50 dark:bg-amber-950/40 border-amber-400 text-amber-700 dark:text-amber-300 shadow-sm'
                : 'bg-slate-50 dark:bg-slate-950 border-slate-200 dark:border-slate-800 text-slate-600 dark:text-slate-400 hover:border-amber-400'
            }`}
          >
            <Code className="w-3.5 h-3.5" />
            <span>{editingLesson.mindmapFile}</span>
            <span className="text-[9px] bg-amber-100 dark:bg-amber-900/40 text-amber-600 px-2 py-0.5 rounded-full">
              {lang === 'ar' ? 'خارطة ذهنية' : 'Mindmap'}
            </span>
          </button>
        )}
        {editingLesson.quizFile && (
          <button
            onClick={() => loadFileForEditing(`${editingLesson.folder}/${editingLesson.quizFile}`)}
            className={`flex items-center gap-2 px-4 py-2.5 rounded-xl text-xs font-black border transition-all ${
              fileEditorPath === `${editingLesson.folder}/${editingLesson.quizFile}`
                ? 'bg-rose-50 dark:bg-rose-950/40 border-rose-400 text-rose-700 dark:text-rose-300 shadow-sm'
                : 'bg-slate-50 dark:bg-slate-950 border-slate-200 dark:border-slate-800 text-slate-600 dark:text-slate-400 hover:border-rose-400'
            }`}
          >
            <FileQuestion className="w-3.5 h-3.5" />
            <span>{editingLesson.quizFile}</span>
            <span className="text-[9px] bg-rose-100 dark:bg-rose-900/40 text-rose-600 px-2 py-0.5 rounded-full">
              {lang === 'ar' ? 'اختبار HTML' : 'HTML Quiz'}
            </span>
          </button>
        )}
        {!editingLesson.mindmapFile && !editingLesson.quizFile && (
          <p className="text-xs text-slate-400 font-bold">{lang === 'ar' ? 'لا توجد ملفات HTML مرتبطة بهذا الدرس.' : 'No HTML files linked to this lesson.'}</p>
        )}
      </div>

      {/* HTML Code Editor */}
      {fileEditorPath && (
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-6 pt-4 border-t border-slate-50 dark:border-slate-800">

          {/* Left Panel: Code Editor (7 cols) */}
          <div className="lg:col-span-7 space-y-3">
            <div className="flex flex-wrap items-center justify-between gap-3 bg-slate-50 dark:bg-slate-950 p-3.5 rounded-2xl border border-slate-200 dark:border-slate-800 shadow-sm">
              {/* Editor Modes Tab */}
              <div className="flex bg-slate-200 dark:bg-slate-850 p-1 rounded-xl">
                <button
                  type="button"
                  onClick={() => setFileEditorTab('easy')}
                  className={`px-3 py-1.5 rounded-lg text-[10px] font-black transition-all ${
                    fileEditorTab === 'easy'
                      ? 'bg-white dark:bg-slate-900 text-slate-800 dark:text-slate-200 shadow-sm'
                      : 'text-slate-500 hover:text-slate-700'
                  }`}
                >
                  {lang === 'ar' ? '✍️ تحرير سهل (تفاعلي)' : '✍️ Easy Edit (Nodes)'}
                </button>
                <button
                  type="button"
                  onClick={() => setFileEditorTab('code')}
                  className={`px-3 py-1.5 rounded-lg text-[10px] font-black transition-all ${
                    fileEditorTab === 'code'
                      ? 'bg-white dark:bg-slate-900 text-slate-800 dark:text-slate-200 shadow-sm'
                      : 'text-slate-500 hover:text-slate-700'
                  }`}
                >
                  {lang === 'ar' ? '💻 كود HTML' : '💻 Code Editor'}
                </button>
              </div>

              {/* Search & Replace controls */}
              <div className="flex items-center gap-1">
                <input 
                  type="text" 
                  placeholder={lang === 'ar' ? 'بحث عن نص...' : 'Find text...'}
                  value={findText}
                  onChange={(e) => setFindText(e.target.value)}
                  className="bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 text-[10px] font-bold px-2 py-1.5 rounded-lg w-24 focus:outline-none focus:border-emerald-500"
                />
                <input 
                  type="text" 
                  placeholder={lang === 'ar' ? 'استبدال بـ...' : 'Replace with...'}
                  value={replaceText}
                  onChange={(e) => setReplaceText(e.target.value)}
                  className="bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 text-[10px] font-bold px-2 py-1.5 rounded-lg w-24 focus:outline-none focus:border-emerald-500"
                />
                <button 
                  type="button"
                  onClick={handleSearchAndReplace}
                  className="bg-emerald-500 hover:bg-emerald-600 text-white text-[9px] font-black px-2 py-1.5 rounded-lg transition-transform active:scale-95"
                >
                  {replaceSuccess ? '✓' : (lang === 'ar' ? 'تبديل' : 'Swap')}
                </button>
              </div>
            </div>

            {/* Easy editor interface */}
            {fileEditorTab === 'easy' && (
              <div className="bg-slate-50 dark:bg-slate-950 p-4 rounded-2xl border border-slate-200 dark:border-slate-800 space-y-4 max-h-[550px] overflow-y-auto">
                <div className="flex items-center justify-between border-b border-slate-200 dark:border-slate-800 pb-2">
                  <span className="text-[10px] font-black text-slate-500 dark:text-slate-450 uppercase tracking-wider">
                    {lang === 'ar' ? '🎯 العقد والنقاط المعرّفة بالملف:' : '🎯 Defined nodes in document:'}
                  </span>
                  <input 
                    type="text" 
                    placeholder={lang === 'ar' ? 'تصفية العقد...' : 'Filter nodes...'}
                    value={nodesSearchQuery}
                    onChange={(e) => setNodesSearchQuery(e.target.value)}
                    className="bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 text-[9px] font-bold px-2 py-1 rounded-lg w-32 focus:outline-none focus:border-emerald-500"
                  />
                </div>
                <div className="space-y-2.5">
                  {mindmapNodes
                    .filter(node => !nodesSearchQuery || node.text.toLowerCase().includes(nodesSearchQuery.toLowerCase()))
                    .map((node) => (
                      <div key={node.index} className="flex gap-2 items-center bg-white dark:bg-slate-900 p-2.5 rounded-xl border border-slate-100 dark:border-slate-850 shadow-sm relative group">
                        <span className="text-[9px] font-mono bg-slate-100 dark:bg-slate-800 text-slate-500 px-1.5 py-0.5 rounded">
                          #{node.index + 1}
                        </span>
                        <span className="text-[9px] font-black text-slate-400 font-mono">
                          [{node.type}]
                        </span>
                        <input
                          type="text"
                          value={node.text}
                          onChange={(e) => handleNodeUpdate(node.index, e.target.value)}
                          className="flex-1 bg-transparent text-xs font-bold text-slate-700 dark:text-slate-300 border-none focus:outline-none pr-6"
                        />
                        <button
                          type="button"
                          onClick={() => handleNodeDelete(node.index)}
                          className="absolute right-2 text-rose-500 hover:text-rose-600 opacity-0 group-hover:opacity-100 transition-opacity"
                          title="Delete Node text"
                        >
                          <Trash2 className="w-3.5 h-3.5" />
                        </button>
                      </div>
                    ))}
                  {mindmapNodes.length === 0 && (
                    <p className="text-center text-slate-400 font-bold text-[10px] py-4">
                      {lang === 'ar' ? 'لا توجد نصوص أو عقد قابلة للتعديل التفاعلي في هذا الملف.' : 'No editable text blocks detected in this file.'}
                    </p>
                  )}
                </div>

                <div className="flex items-center justify-between border-t border-slate-200 dark:border-slate-800 pt-3">
                  <span className="text-[9px] text-slate-450 dark:text-slate-500 font-bold">
                    {lang === 'ar' 
                      ? '⚠️ التغييرات تُحفظ كلياً بالملف في السيرفر.' 
                      : '⚠️ Node changes are written to server file.'}
                  </span>
                  <button
                    type="button"
                    onClick={async () => {
                      setDeleteSuccess(true);
                      await handleBatchReplace();
                      setTimeout(() => setDeleteSuccess(false), 2000);
                    }}
                    disabled={mindmapNodes.length === 0}
                    className="flex items-center gap-1 bg-emerald-500 hover:bg-emerald-600 text-white text-[9px] font-black px-3 py-1.5 rounded-lg transition-all active:scale-95"
                  >
                    {deleteSuccess ? <Check className="w-4 h-4" /> : <Trash2 className="w-4 h-4" />}
                    <span>{deleteSuccess ? (lang === 'ar' ? 'تم الحفظ ✓' : 'Saved ✓') : (lang === 'ar' ? 'حفظ تعديلات العقد' : 'Save Node Edits')}</span>
                  </button>
                </div>
              </div>
            )}

            {/* Code Editor */}
            {fileEditorTab === 'code' && (
              <div className="space-y-2">
                <div className="space-y-0 rounded-xl overflow-hidden border border-slate-200 dark:border-slate-800">
                  <div className="flex items-center justify-between bg-slate-900 dark:bg-slate-950 px-4 py-2.5">
                    <span className="text-[10px] font-black text-slate-400 font-mono truncate">{fileEditorPath}</span>
                    <button
                      type="button"
                      onClick={saveFileContent}
                      disabled={fileEditorSaving}
                      className="flex items-center gap-1.5 bg-emerald-500 hover:bg-emerald-600 text-white text-[10px] font-black px-3 py-1.5 rounded-lg transition-colors active:scale-95 shrink-0"
                    >
                      {fileEditorSaving
                        ? <RefreshCw className="w-3 h-3 animate-spin" />
                        : fileEditorSaved
                          ? <CheckCircle className="w-3 h-3" />
                          : <Save className="w-3 h-3" />
                      }
                      <span>
                        {fileEditorSaving
                          ? (lang === 'ar' ? 'جارٍ الحفظ...' : 'Saving...')
                          : fileEditorSaved
                            ? (lang === 'ar' ? 'تم الحفظ ✓' : 'Saved ✓')
                            : (lang === 'ar' ? 'حفظ التعديلات' : 'Save File')
                        }
                      </span>
                    </button>
                  </div>
                  {fileEditorLoading ? (
                    <div className="bg-slate-950 h-64 flex items-center justify-center">
                      <RefreshCw className="w-6 h-6 text-slate-500 animate-spin" />
                    </div>
                  ) : (
                    <textarea
                      value={fileEditorContent}
                      onChange={(e) => setFileEditorContent(e.target.value)}
                      spellCheck={false}
                      dir="ltr"
                      className="w-full bg-slate-950 text-emerald-300 font-mono text-[11px] leading-relaxed p-4 border-t border-slate-800 focus:outline-none focus:border-emerald-600 h-[420px] resize-y"
                      placeholder="<!-- محتوى الملف سيظهر هنا -->"
                    />
                  )}
                </div>
                <p className="text-[9px] text-slate-400 font-semibold">
                  {lang === 'ar'
                    ? '💡 عدّل الكود مباشرة ثم اضغط «حفظ التعديلات» ليُكتب الملف فوراً على السيرفر.'
                    : '💡 Edit the code directly then click Save — the file is written immediately to disk.'}
                </p>
              </div>
            )}
          </div>

          {/* Right Panel: Interactive Mindmap Preview (5 cols) */}
          <div className="lg:col-span-5 space-y-3">
            <div className="border border-slate-200 dark:border-slate-800 rounded-2xl overflow-hidden bg-white dark:bg-slate-950 flex flex-col h-[670px] shadow-sm">
              <div className="bg-slate-50 dark:bg-slate-900/60 px-4 py-3 border-b border-slate-205 dark:border-slate-800 flex items-center justify-between">
                <span className="text-[10px] font-black text-slate-700 dark:text-slate-300 flex items-center gap-1.5">
                  <span>🖥️</span>
                  <span>{lang === 'ar' ? 'معاينة تفاعلية للخريطة الذهنية' : 'Interactive Mindmap Preview'}</span>
                </span>
                <button
                  type="button"
                  onClick={() => setIframeKey(prev => prev + 1)}
                  className="text-slate-400 hover:text-emerald-500 p-1 rounded transition-colors active:scale-95"
                  title={lang === 'ar' ? 'تحديث المعاينة' : 'Refresh Preview'}
                >
                  <RefreshCw className="w-3.5 h-3.5" />
                </button>
              </div>
              <iframe 
                ref={iframeRef}
                onLoad={onIframeLoad}
                key={iframeKey}
                src={`/${fileEditorPath}`}
                className="w-full flex-1 border-none bg-slate-950"
                title="Mindmap Preview"
              />
            </div>
            <p className="text-[9px] text-slate-400 font-semibold leading-relaxed">
              {lang === 'ar'
                ? '💡 هذه نافذة معاينة مباشرة للخريطة الذهنية كما ستظهر للطلاب. بمجرد قيامك بحفظ التعديلات من المحرر على اليسار، ستتحدث المعاينة هنا تلقائياً لترى النتيجة.'
                : '💡 This is a live preview window of the mindmap. Once you save edits on the left, the preview reloads automatically.'}
            </p>
          </div>
        </div>
      )}
    </div>

    {/* ── Binary Files Section (Images & PDFs) ─────────────── */}
    <div className="space-y-3 border-t border-slate-50 dark:border-slate-800 pt-4">
      <p className="text-[10px] font-black text-slate-400 uppercase tracking-wider">
        {lang === 'ar' ? 'الصور وملفات PDF — استبدال مباشر' : 'Images & PDFs — Direct Replacement'}
      </p>
      <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">

        {/* Diagram */}
        <div className="bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 rounded-2xl p-4 space-y-2">
          <div className="flex items-center gap-2">
            <span className="text-lg">🖼️</span>
            <div>
              <p className="text-[10px] font-black text-slate-700 dark:text-slate-300">{lang === 'ar' ? 'رسم الدرس التخطيطي' : 'Lesson Diagram'}</p>
              <p className="text-[9px] text-slate-400 font-mono">{editingLesson.diagramFile || '—'}</p>
            </div>
          </div>
          <button
            onClick={() => handleFileUpload('diagramFile', 'image/*')}
            disabled={uploadingField === 'diagramFile'}
            className="w-full flex items-center justify-center gap-2 bg-white dark:bg-slate-900 hover:bg-emerald-50 dark:hover:bg-emerald-950/30 border border-slate-200 dark:border-slate-700 hover:border-emerald-400 text-slate-600 dark:text-slate-300 hover:text-emerald-600 font-black text-xs py-2.5 rounded-xl transition-all active:scale-95"
          >
            {uploadingField === 'diagramFile' ? <RefreshCw className="w-4 h-4 animate-spin" /> : uploadSuccess === 'diagramFile' ? <CheckCircle className="w-4 h-4 text-emerald-500" /> : <FolderOpen className="w-4 h-4" />}
            {uploadSuccess === 'diagramFile' ? (lang === 'ar' ? 'تم الرفع بنجاح ✓' : 'Uploaded ✓') : (lang === 'ar' ? 'رفع صورة جديدة' : 'Upload New Image')}
          </button>
        </div>

        {/* Summary */}
        <div className="bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 rounded-2xl p-4 space-y-2">
          <div className="flex items-center gap-2">
            <span className="text-lg">📊</span>
            <div>
              <p className="text-[10px] font-black text-slate-700 dark:text-slate-300">{lang === 'ar' ? 'إنفوجرافيك الملخص' : 'Summary Infographic'}</p>
              <p className="text-[9px] text-slate-400 font-mono">{editingLesson.summaryFile || '—'}</p>
            </div>
          </div>
          <button
            onClick={() => handleFileUpload('summaryFile', 'image/*')}
            disabled={uploadingField === 'summaryFile'}
            className="w-full flex items-center justify-center gap-2 bg-white dark:bg-slate-900 hover:bg-emerald-50 dark:hover:bg-emerald-950/30 border border-slate-200 dark:border-slate-700 hover:border-emerald-400 text-slate-600 dark:text-slate-300 hover:text-emerald-600 font-black text-xs py-2.5 rounded-xl transition-all active:scale-95"
          >
            {uploadingField === 'summaryFile' ? <RefreshCw className="w-4 h-4 animate-spin" /> : uploadSuccess === 'summaryFile' ? <CheckCircle className="w-4 h-4 text-emerald-500" /> : <FolderOpen className="w-4 h-4" />}
            {uploadSuccess === 'summaryFile' ? (lang === 'ar' ? 'تم الرفع بنجاح ✓' : 'Uploaded ✓') : (lang === 'ar' ? 'رفع صورة جديدة' : 'Upload New Image')}
          </button>
        </div>

        {/* PDF */}
        <div className="bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 rounded-2xl p-4 space-y-2 sm:col-span-2">
          <div className="flex items-center gap-2">
            <span className="text-lg">📄</span>
            <div>
              <p className="text-[10px] font-black text-slate-700 dark:text-slate-300">{lang === 'ar' ? 'ملف PDF الدرس' : 'Lesson PDF File'}</p>
              <p className="text-[9px] text-slate-400 font-mono">{editingLesson.pdfFile || '—'}</p>
            </div>
          </div>
          <button
            onClick={() => handleFileUpload('pdfFile', '.pdf,application/pdf')}
            disabled={uploadingField === 'pdfFile'}
            className="w-full flex items-center justify-center gap-2 bg-white dark:bg-slate-900 hover:bg-emerald-50 dark:hover:bg-emerald-950/30 border border-slate-200 dark:border-slate-700 hover:border-emerald-400 text-slate-600 dark:text-slate-300 hover:text-emerald-600 font-black text-xs py-2.5 rounded-xl transition-all active:scale-95"
          >
            {uploadingField === 'pdfFile' ? <RefreshCw className="w-4 h-4 animate-spin" /> : uploadSuccess === 'pdfFile' ? <CheckCircle className="w-4 h-4 text-emerald-500" /> : <FolderOpen className="w-4 h-4" />}
            {uploadSuccess === 'pdfFile' ? (lang === 'ar' ? 'تم الرفع بنجاح ✓' : 'Uploaded ✓') : (lang === 'ar' ? 'رفع PDF جديد' : 'Upload New PDF')}
          </button>
        </div>

      </div>
    </div>
  </div>
)}
